type SourceGate = { source_id: string; enabled: boolean; requires_approval: boolean; tenant_plan: string; note: string };
type GeneralSettingsState = { application_name: string; public_url: string; support_email: string; default_plan: string; require_consent: boolean; normalized_evidence_only: boolean; high_cost_provider_approval: boolean; export_retention_days: number };
type RouteSettingsState = { mode: "off" | "provider" | "manual"; manual_entries: string[]; use_only_for_allowlisted_egress: boolean; disable_failed_proxies: boolean; require_admin_approval: boolean; health_check_interval_minutes: number };
type RouteRouteRule = { id: string; label: string; category: string; enabled: boolean; proxy_required: boolean; provider_ids: string[]; allowed_domains: string[]; note: string };
type RouteConnectionResult = { index: number; proxy: string; ok: boolean; status: "connected" | "failed" | "invalid_format" | "skipped"; latency_ms?: number | null; http_status?: number | null; error: string; target_url: string };
type RouteConnectionTestResponse = { ok: boolean; tested: number; connected: number; failed: number; target_url: string; results: RouteConnectionResult[]; message: string };
type ContactSubmissionRecord = { id: string; name: string; email: string; company: string; message: string; status: string; received_at: string };
type AuditEvent = Record<string, string>;
type AuthResponse = { ok: boolean; role: "member" | "admin"; display_name: string; token: string; message: string };
