type BillingPlan = { id: string; name: string; amount: number; currency: string; interval: "month" | "year" | "one_time"; monthly_search_limit: number; export_enabled: boolean; api_access_enabled: boolean; description: string; services: string[]; enabled: boolean; public: boolean; paypal_item_name: string; sort_order: number };
