type SourceHealth = { source_id: string; status: string; latency_ms?: number | null; last_checked_at: string; note: string };
type UserAccountView = { username: string; email: string; role: string; tenant_id: string; plan: string; active: boolean; failed_attempts: number; locked_until?: string | null };
type TenantAccount = { id: string; name: string; plan: string; monthly_search_limit: number; status: "active" | "pending" | "suspended" };
type MemberDashboardSummary = { user: UserAccountView; tenant: TenantAccount; plan: BillingPlan; searches_this_month: number; reports_exported: number; enabled_sources: number; recent_jobs: SearchJob[]; source_health: SourceHealth[]; billing_status: string; plan_features: string[] };
type MailSettingsState = { provider: string; from_email: string; smtp_api_key_ref: string; password_reset_enabled: boolean; contact_notifications_enabled: boolean };
type LaunchChecklistItem = { id: string; label: string; status: "done" | "partial" | "blocked" | "todo"; owner: string; note: string };
type DeploymentHardeningStatus = { https_only_cookies: boolean; csrf_required_for_admin: boolean; cors_locked_down: boolean; vault_only_secrets: boolean; container_health_checks: boolean; automated_backups: boolean; note: string };
type ComplianceSettingsState = { tenant_controls_enabled: boolean; require_consent_record: boolean; require_source_attribution: boolean; default_use_case: string; allowed_geographies: string[]; approval_required_for_sensitive_sources: boolean; reviewer_role_enabled: boolean; note: string };
type UsageControlSettingsState = { queue_enabled: boolean; max_concurrent_jobs: number; monthly_cost_alert_threshold: number; high_cost_provider_alerts: boolean; notify_billing_contact: boolean; automatic_pause_on_limit: boolean; note: string };

type Workspace = ReturnType<typeof useWorkspace>;
const API_BASE_URL = import.meta.env.VITE_API_BASE_URL ?? "";
const PAYPAL_EMAIL = "techpronow@gmail.com";
const PAYPAL_URL = "https://www.paypal.com/cgi-bin/webscr?cmd=_xclick&business=techpronow%40gmail.com&currency_code=USD&item_name=Social%20Hunter%20SaaS";
async function api<T>(path: string, init?: RequestInit): Promise<T> {
  const token = localStorage.getItem("socialHunterToken");
  const headers: Record<string, string> = { "Content-Type": "application/json" };
  if (token) headers.Authorization = `Bearer ${token}`;
  const res = await fetch(`${API_BASE_URL}${path}`, { ...init, headers });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) throw new Error(data.detail ?? `Request failed: ${path}`);
  return data as T;
}

function clearSession() { localStorage.removeItem("socialHunterToken"); localStorage.removeItem("socialHunterRole"); }
function hasStoredSession(role: "member" | "admin") { return Boolean(localStorage.getItem("socialHunterToken")) && localStorage.getItem("socialHunterRole") === role; }
function CheckingAccess({ label }: { label: string }) { return <main className="auth-page"><section className="auth-panel admin-login"><span className="eyebrow">Checking access</span><h1>{label}</h1><p>Verifying your session before loading the dashboard.</p></section></main>; }
const defaultBillingPlans: BillingPlan[] = [{ id: "starter", name: "Starter", amount: 49, currency: "USD", interval: "month", monthly_search_limit: 250, export_enabled: true, api_access_enabled: false, description: "Entry plan for small public-source research workflows.", services: ["250 searches per month", "Dashboard access", "JSON and CSV exports"], enabled: true, public: true, paypal_item_name: "Social Hunter Starter Plan", sort_order: 10 }, { id: "growth", name: "Growth", amount: 149, currency: "USD", interval: "month", monthly_search_limit: 1500, export_enabled: true, api_access_enabled: false, description: "Team plan for recurring account, domain, and contact verification workflows.", services: ["1,500 searches per month", "Member dashboard", "Report exports", "Provider health checks"], enabled: true, public: true, paypal_item_name: "Social Hunter Growth Plan", sort_order: 20 }, { id: "operator", name: "Operator", amount: 399, currency: "USD", interval: "month", monthly_search_limit: 7500, export_enabled: true, api_access_enabled: true, description: "Operator plan for higher-volume teams that need API access and advanced provider configuration.", services: ["7,500 searches per month", "API access", "Advanced source controls", "Audit and compliance exports"], enabled: true, public: true, paypal_item_name: "Social Hunter Operator Plan", sort_order: 30 }];
const platformCapabilities = ["Tenant-aware access with owner, analyst, billing, and read-only reviewer roles.", "Protected provider credentials stored as secure references with provider health status.", "PayPal plan controls with subscription-ready billing and payment-status gates.", "Audit logs for searches, exports, admin setting changes, and consent confirmations.", "Source-level compliance controls by tenant, geography, provider, and use case.", "Queued jobs, usage caps, and alerts that protect high-cost enrichment credits."];
const sampleFindings: Finding[] = [{ id: "1", source: "GitHub", category: "developer", status: "found", confidence: 0.86, title: "GitHub profile check", url: "https://github.com/socialhunter", evidence: "Example public signal indicates a likely profile match.", compliance_flags: ["public_source", "no_bypass", "no_raw_secret"] }, { id: "2", source: "HIBP", category: "breach", status: "skipped", confidence: 0, title: "Breach lookup not enabled", evidence: "Add a secure provider credential and terms review before enabling breach lookup.", compliance_flags: ["api_terms_required", "no_raw_secret"] }];
