function routeFromPath(): Route { const p = window.location.pathname.replace(/\/+$/, ""); if (p.endsWith("/members")) return "members"; if (p.endsWith("/social-hunter-admin")) return "admin"; return "home"; }
function go(path: string) { window.history.pushState({}, "", path); window.dispatchEvent(new PopStateEvent("popstate")); }
function App() { const [route, setRoute] = React.useState<Route>(routeFromPath); const [menu, setMenu] = React.useState(false); React.useEffect(() => { const f = () => setRoute(routeFromPath()); window.addEventListener("popstate", f); return () => window.removeEventListener("popstate", f); }, []); return <><TopNav route={route} menu={menu} setMenu={setMenu} />{route === "home" && <Landing />}{route === "members" && <Members />}{route === "admin" && <Admin />}</>; }
function TopNav({ route, menu, setMenu }: { route: Route; menu: boolean; setMenu: (v: boolean) => void }) { const links = [["Home", "/"], ["Members", "/members/"], ["Pricing", "/#pricing"], ["About", "/#about"], ["Contact", "/#contact"]]; return <header className="floating-nav"><button className="brand-button" onClick={() => go("/")}><ShieldCheck size={22} />Social Hunter</button><nav className={menu ? "nav-links open" : "nav-links"}>{links.map(([label, href]) => <a key={label} href={href} className={(route === "members" && label === "Members") || (route === "home" && label === "Home") ? "active" : ""} onClick={(e) => { e.preventDefault(); setMenu(false); go(href); }}>{label}</a>)}</nav><button className="icon-button mobile-only" onClick={() => setMenu(!menu)}>{menu ? <X /> : <Menu />}</button></header>; }
function Landing() { const [plans, setPlans] = React.useState<BillingPlan[]>(defaultBillingPlans); React.useEffect(() => { api<BillingPlan[]>('/api/plans').then(setPlans).catch(() => undefined); }, []); return <main className="site-page"><section className="hero-section"><div className="hero-copy"><span className="eyebrow">Public-source intelligence for business teams</span><h1>Social Hunter</h1><p>Find, verify, and organize public contact, profile, domain, and company signals from approved APIs and public data sources.</p><div className="hero-actions"><button className="primary-button" onClick={() => go('/members/')}><UserRound size={18} />Member Login</button><a className="secondary-link" href="#pricing">View Pricing</a></div></div><ProductPreview /></section><section className="section-band" id="about"><SectionTitle eyebrow="Why clients use it" title="One workspace for compliant lead and account research." /><div className="benefit-grid"><Feature icon={<Search />} title="Find public signals" copy="Search usernames, emails, domains, phone numbers, IPs, and businesses from connected providers." /><Feature icon={<CheckCircle2 />} title="Validate before outreach" copy="Normalize records, score confidence, and separate verified results from weak signals." /><Feature icon={<Archive />} title="Export evidence" copy="Create clean reports for sales, recruiting, fraud review, and internal research workflows." /><Feature icon={<ShieldCheck />} title="Control compliance" copy="Keep sources gated by terms, consent, tenant plan, and admin-approved credentials." /></div></section><section className="pricing-section" id="pricing"><SectionTitle centered eyebrow="Pricing" title="Simple monthly plans paid through PayPal." copy={`Payments route to ${PAYPAL_EMAIL}. Member access, plan limits, and billing status are managed from the admin dashboard.`} /><div className="pricing-grid">{plans.map((p) => <article className="price-card" key={p.id}><h3>{p.name}</h3><div className="price"><span>{`$${p.amount}`}</span>/{p.interval === 'one_time' ? 'once' : p.interval}</div><p>{p.description || `${p.monthly_search_limit.toLocaleString()} searches for lawful public-source research workflows.`}</p><ul className="price-services">{p.services.slice(0, 4).map((service) => <li key={service}>{service}</li>)}</ul><a className="primary-button full" href={`https://www.paypal.com/cgi-bin/webscr?cmd=_xclick&business=${encodeURIComponent(PAYPAL_EMAIL)}&currency_code=${p.currency}&item_name=${encodeURIComponent(p.paypal_item_name || `Social Hunter ${p.name} Plan`)}&amount=${p.amount}`} target="_blank" rel="noreferrer"><CreditCard size={18} />Pay with PayPal</a></article>)}</div></section><section className="section-band recommendations"><SectionTitle eyebrow="Platform controls" title="SaaS controls included for managed research teams." /><ol className="recommendation-list">{platformCapabilities.map((r) => <li key={r}>{r}</li>)}</ol></section><section className="contact-section" id="contact"><div><span className="eyebrow">Contact</span><h2>Request access or ask about a team rollout.</h2><p>Form submissions appear in the admin contact mailbox after submission.</p></div><ContactForm /></section></main>; }
function ProductPreview() { return <div className="hero-dashboard"><div className="browser-bar"><span /><span /><span /></div><div className="preview-search"><Search size={18} /><span>domain: clientcompany.com</span><strong>92%</strong></div><div className="preview-grid"><Metric label="Profiles checked" value="184" /><Metric label="Verified emails" value="37" /><Metric label="Risk flags" value="6" /></div><div className="preview-list"><Preview label="GitHub public profile" status="found" /><Preview label="Business records" status="found" /><Preview label="HIBP exposure check" status="review" /></div></div>; }
function SectionTitle({ eyebrow, title, copy, centered }: { eyebrow: string; title: string; copy?: string; centered?: boolean }) { return <div className={centered ? "section-heading centered" : "section-heading"}><span className="eyebrow">{eyebrow}</span><h2>{title}</h2>{copy && <p>{copy}</p>}</div>; }
function Feature({ icon, title, copy }: { icon: React.ReactNode; title: string; copy: string }) { return <article className="feature-card">{icon}<h3>{title}</h3><p>{copy}</p></article>; }
function Metric({ label, value }: { label: string; value: string }) { return <div><strong>{value}</strong><span>{label}</span></div>; }
function Preview({ label, status }: { label: string; status: string }) { return <div className="preview-row"><span>{label}</span><strong>{status}</strong></div>; }
function ResetPasswordPanel({ role, endpoint, placeholder }: { role: "member" | "admin"; endpoint: string; placeholder: string }) { const [email, setEmail] = React.useState(""); const [status, setStatus] = React.useState<"idle" | "sending" | "sent" | "error">("idle"); const [message, setMessage] = React.useState(""); async function requestReset(e: React.FormEvent) { e.preventDefault(); setStatus("sending"); setMessage(""); try { const res = await fetch(`${API_BASE_URL}${endpoint}`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ email }) }); const data = await res.json().catch(() => ({})); if (!res.ok) throw new Error(data.detail ?? "Password reset request failed"); setStatus("sent"); setMessage(data.message ?? "Password reset email request queued."); } catch (err) { setStatus("error"); setMessage(err instanceof Error ? err.message : "Password reset request failed"); } } return <form className="reset-panel" onSubmit={requestReset}><div><Mail size={22} /><div><strong>Reset {role} password by email</strong><span>Enter the email on the account and the reset workflow will send instructions once mail is configured.</span></div></div><label>Email address<input required type="email" value={email} onChange={(e) => setEmail(e.target.value)} placeholder={placeholder} autoComplete="email" /></label><button className="secondary-button full" disabled={status === "sending"}><Mail size={18} />{status === "sending" ? "Sending reset request" : "Email reset instructions"}</button>{message && <p className={status === "error" ? "error-state" : "success-state"}>{message}</p>}</form>; }
function Members() { const [signedIn, setSignedIn] = React.useState(false); const [checking, setChecking] = React.useState(hasStoredSession("member")); const [view, setView] = React.useState<MemberView>("dashboard"); const [login, setLogin] = React.useState({ username: "member", password: "member" }); const [signup, setSignup] = React.useState({ name: "", email: "", company: "", plan: "growth" }); const [error, setError] = React.useState(""); const [signupMessage, setSignupMessage] = React.useState(""); const [checkoutUrl, setCheckoutUrl] = React.useState(""); const [signupBusy, setSignupBusy] = React.useState(false); React.useEffect(() => { let active = true; if (!hasStoredSession("member")) { setChecking(false); return; } api<AuthVerifyResponse>("/api/auth/member/verify").then((res) => { if (!active) return; if (res.ok && res.role === "member") setSignedIn(true); else clearSession(); }).catch(() => { if (active) clearSession(); }).finally(() => { if (active) setChecking(false); }); return () => { active = false; }; }, []); async function submit(e: React.FormEvent) { e.preventDefault(); setError(""); try { const auth = await api<AuthResponse>("/api/auth/member/login", { method: "POST", body: JSON.stringify(login) }); localStorage.setItem("socialHunterToken", auth.token); localStorage.setItem("socialHunterRole", auth.role); const verified = await api<AuthVerifyResponse>("/api/auth/member/verify"); if (verified.role !== "member") throw new Error("Member access verification failed"); setSignedIn(true); } catch (err) { clearSession(); setError(err instanceof Error ? err.message : "Sign in failed"); } } async function submitSignup(e: React.FormEvent) { e.preventDefault(); setSignupBusy(true); setSignupMessage(""); setCheckoutUrl(""); try { const response = await api<{ status: string; message: string }>("/api/auth/member/signup", { method: "POST", body: JSON.stringify(signup) }); const checkout = await api<PayPalCheckoutResponse>("/api/billing/paypal/checkout", { method: "POST", body: JSON.stringify({ plan: signup.plan, email: signup.email }) }); setCheckoutUrl(checkout.checkout_url); setSignupMessage(`${response.message} ${checkout.message}`); } catch (err) { setSignupMessage(err instanceof Error ? err.message : "Signup request failed"); } finally { setSignupBusy(false); } } if (checking) return <CheckingAccess label="Member Dashboard" />; if (signedIn) return <MemberDashboard view={view} setView={setView} />; return <main className="auth-page"><section className="auth-layout"><div className="auth-panel"><span className="eyebrow">Members</span><h1>Sign in to your dashboard</h1><form className="form-stack" onSubmit={submit}><label>Username or email<input required autoComplete="username" placeholder="member@example.com" value={login.username} onChange={(e) => setLogin({ ...login, username: e.target.value })} /></label><label>Password<input required type="password" autoComplete="current-password" placeholder="Password" value={login.password} onChange={(e) => setLogin({ ...login, password: e.target.value })} /></label><button className="primary-button full"><LockKeyhole size={18} />Sign in</button>{error && <p className="error-state">{error}</p>}</form><ResetPasswordPanel role="member" endpoint="/api/auth/member/password-reset" placeholder="member@example.com" /></div><div className="signup-panel"><UserPlus size={30} /><h2>Need an account?</h2><p>Create a member request, choose a plan, and continue to PayPal checkout.</p><form className="form-stack" onSubmit={submitSignup}><label>Name<input required value={signup.name} onChange={(e) => setSignup({ ...signup, name: e.target.value })} placeholder="Your name" /></label><label>Email<input required type="email" value={signup.email} onChange={(e) => setSignup({ ...signup, email: e.target.value })} placeholder="you@company.com" /></label><label>Company<input value={signup.company} onChange={(e) => setSignup({ ...signup, company: e.target.value })} placeholder="Company" /></label><label>Plan<select value={signup.plan} onChange={(e) => setSignup({ ...signup, plan: e.target.value })}><option value="starter">Starter</option><option value="growth">Growth</option><option value="operator">Operator</option></select></label><button className="secondary-button full" disabled={signupBusy}><CreditCard size={18} />{signupBusy ? "Creating request" : "Create request and checkout"}</button>{signupMessage && <p className="success-state">{signupMessage}</p>}{checkoutUrl && <a className="primary-button full" href={checkoutUrl} target="_blank" rel="noreferrer"><CreditCard size={18} />Open PayPal checkout</a>}</form></div></section></main>; }
function Admin() { const [signedIn, setSignedIn] = React.useState(false); const [checking, setChecking] = React.useState(hasStoredSession("admin")); const [view, setView] = React.useState<AdminView>("overview"); const [login, setLogin] = React.useState({ username: "admin", password: "admin" }); const [error, setError] = React.useState(""); React.useEffect(() => { let active = true; if (!hasStoredSession("admin")) { setChecking(false); return; } api<AuthVerifyResponse>("/api/auth/admin/verify").then((res) => { if (!active) return; if (res.ok && res.role === "admin") setSignedIn(true); else clearSession(); }).catch(() => { if (active) clearSession(); }).finally(() => { if (active) setChecking(false); }); return () => { active = false; }; }, []); async function submit(e: React.FormEvent) { e.preventDefault(); setError(""); try { const auth = await api<AuthResponse>("/api/auth/admin/login", { method: "POST", body: JSON.stringify(login) }); localStorage.setItem("socialHunterToken", auth.token); localStorage.setItem("socialHunterRole", auth.role); const verified = await api<AuthVerifyResponse>("/api/auth/admin/verify"); if (verified.role !== "admin") throw new Error("Admin access verification failed"); setSignedIn(true); } catch (err) { clearSession(); setError(err instanceof Error ? err.message : "Admin sign in failed"); } } if (checking) return <CheckingAccess label="Admin Dashboard" />; if (signedIn) return <AdminDashboard view={view} setView={setView} />; return <main className="auth-page"><section className="auth-panel admin-login"><span className="eyebrow">Admin</span><h1>Social Hunter Admin</h1><p>Restricted configuration gateway for platform operators.</p><form className="form-stack" onSubmit={submit}><label>Admin username<input required autoComplete="username" value={login.username} onChange={(e) => setLogin({ ...login, username: e.target.value })} /></label><label>Password<input required type="password" autoComplete="current-password" value={login.password} onChange={(e) => setLogin({ ...login, password: e.target.value })} /></label><button className="primary-button full"><LockKeyhole size={18} />Enter admin dashboard</button>{error && <p className="error-state">{error}</p>}</form><ResetPasswordPanel role="admin" endpoint="/api/auth/admin/password-reset" placeholder="admin@example.com" /></section></main>; }
function useWorkspace() { const [targetType, setTargetType] = React.useState<TargetType>("username"); const [target, setTarget] = React.useState("socialhunter"); const [consent, setConsent] = React.useState(true); const [findings, setFindings] = React.useState<Finding[]>(sampleFindings); const [selectedId, setSelectedId] = React.useState("1"); const [sources, setSources] = React.useState(fallbackSources); const [category, setCategory] = React.useState("all"); const [loading, setLoading] = React.useState(false); const [error, setError] = React.useState(""); React.useEffect(() => { fetch(`${API_BASE_URL}/api/sources`).then((r) => r.json()).then(setSources).catch(() => undefined); }, []); async function runSearch(e: React.FormEvent) { e.preventDefault(); setLoading(true); setError(""); try { const res = await fetch(`${API_BASE_URL}/api/search`, { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ target_type: targetType, target, consent_confirmed: consent, dry_run: true }) }); if (!res.ok) throw new Error("Search failed"); const data = await res.json(); setFindings(data.findings ?? sampleFindings); setSelectedId((data.findings ?? sampleFindings)[0]?.id ?? ""); } catch (err) { setError(err instanceof Error ? err.message : "Search failed"); } finally { setLoading(false); } } function exportReport(format: string) { const blob = new Blob([JSON.stringify({ target, findings, format }, null, 2)], { type: "application/json" }); const url = URL.createObjectURL(blob); const a = document.createElement("a"); a.href = url; a.download = `social-hunter-${format}.json`; a.click(); URL.revokeObjectURL(url); } const categories = ["all", ...Array.from(new Set(findings.map((f) => f.category)))]; const results = category === "all" ? findings : findings.filter((f) => f.category === category); const selected = results.find((f) => f.id === selectedId) ?? results[0]; return { targetType, setTargetType, target, setTarget, consent, setConsent, findings, selectedId, setSelectedId, sources, category, setCategory, loading, error, runSearch, exportReport, categories, results, selected }; }
function Shell({ title, subtitle, nav, active, onNav, children }: { title: string; subtitle: string; nav: { id: string; label: string; icon: React.ReactNode }[]; active: string; onNav: (id: string) => void; children: React.ReactNode }) { function exitWorkspace() { clearSession(); go("/"); } return <main className="app-shell"><aside className="sidebar"><button className="brand side-brand" onClick={() => go("/")}><ShieldCheck size={24} />Social Hunter</button><nav>{nav.map((item) => <button key={item.id} className={active === item.id ? "nav-item active" : "nav-item"} onClick={() => onNav(item.id)}>{item.icon}{item.label}</button>)}</nav><div className="policy-box"><strong>Controlled workspace</strong><span>Approved sources, tenant controls, and evidence-first reporting.</span></div></aside><section className="workspace"><header className="topbar"><div><h1>{title}</h1><p>{subtitle}</p></div><button className="operator" onClick={exitWorkspace}><UserRound size={18} />Sign out</button></header>{children}</section></main>; }
function useMemberSummary() { const [summary, setSummary] = React.useState<MemberDashboardSummary | null>(null); const [error, setError] = React.useState(""); React.useEffect(() => { api<MemberDashboardSummary>("/api/member/dashboard").then(setSummary).catch((err) => setError(err instanceof Error ? err.message : "Could not load member dashboard")); }, []); return { summary, error, reload: () => api<MemberDashboardSummary>("/api/member/dashboard").then(setSummary).catch((err) => setError(err instanceof Error ? err.message : "Could not load member dashboard")) }; }
function MemberDashboard({ view, setView }: { view: MemberView; setView: (v: MemberView) => void }) { const w = useWorkspace(); const member = useMemberSummary(); return <Shell title="Member Dashboard" subtitle="Run searches, review reports, manage billing, and monitor enabled data sources." nav={[{ id: "dashboard", label: "Dashboard", icon: <Gauge size={18} /> }, { id: "search", label: "Search", icon: <Search size={18} /> }, { id: "reports", label: "Reports", icon: <Archive size={18} /> }, { id: "sources", label: "Sources", icon: <Database size={18} /> }, { id: "billing", label: "Billing", icon: <CreditCard size={18} /> }, { id: "account", label: "Account", icon: <UserRound size={18} /> }]} active={view} onNav={(id) => setView(id as MemberView)}>{member.error && <p className="error-state">{member.error}</p>}{view === "dashboard" && <MemberOverview w={w} summary={member.summary} />}{view === "search" && <SearchWorkspace w={w} />}{view === "reports" && <ReportsView w={w} />}{view === "sources" && <SourcesView sources={w.sources} health={member.summary?.source_health ?? []} />}{view === "billing" && <MemberBillingPage summary={member.summary} />}{view === "account" && <MemberAccountPage summary={member.summary} />}</Shell>; }
function AdminDashboard({ view, setView }: { view: AdminView; setView: (v: AdminView) => void }) { const w = useWorkspace(); return <Shell title="Admin Dashboard" subtitle="Configure SaaS settings, integrations, provider routing, compliance, usage, mail, billing, users, and audit controls." nav={[{ id: "overview", label: "Overview", icon: <Gauge size={18} /> }, { id: "general", label: "General Settings", icon: <Settings size={18} /> }, { id: "api", label: "Integrations", icon: <KeyRound size={18} /> }, { id: "proxy", label: "Provider Routing", icon: <Network size={18} /> }, { id: "compliance", label: "Compliance", icon: <ShieldCheck size={18} /> }, { id: "usage", label: "Usage Controls", icon: <SlidersHorizontal size={18} /> }, { id: "mail", label: "Contact Mail", icon: <Mail size={18} /> }, { id: "users", label: "Users", icon: <UsersRound size={18} /> }, { id: "billing", label: "Billing", icon: <CreditCard size={18} /> }, { id: "audit", label: "Audit", icon: <Activity size={18} /> }]} active={view} onNav={(id) => setView(id as AdminView)}>{view === "overview" && <AdminOverview w={w} />}{view === "general" && <GeneralSettings />}{view === "api" && <ApiSettings />}{view === "proxy" && <RouteSettings />}{view === "compliance" && <CompliancePage />}{view === "usage" && <UsageControlsPage />}{view === "mail" && <ContactMail />}{view === "users" && <UsersPage />}{view === "billing" && <BillingPage />}{view === "audit" && <AuditPage />}</Shell>; }
function MemberOverview({ w, summary }: { w: Workspace; summary: MemberDashboardSummary | null }) { const sourceCount = summary?.enabled_sources ?? w.sources.filter((s) => s.status !== "disabled").length; return <section className="dashboard-grid single"><div className="metric-strip cards"><Metric label="Searches this month" value={String(summary?.searches_this_month ?? 0)} /><Metric label="Reports exported" value={String(summary?.reports_exported ?? 0)} /><Metric label="Enabled sources" value={String(sourceCount)} /></div><section className="content-panel"><SectionTitle eyebrow="Account" title={summary ? `${summary.user.username} / ${summary.plan.name}` : "Loading account"} copy={summary ? `${summary.tenant.name} is ${summary.billing_status}. Monthly search limit: ${summary.plan.monthly_search_limit.toLocaleString()}.` : "Loading member account, tenant, and billing state."} /><div className="readiness-row">{(summary?.plan_features ?? []).slice(0, 6).map((feature) => <span className="status ready" key={feature}>{feature}</span>)}</div></section><section className="content-panel"><SectionTitle eyebrow="Recent search" title={w.target} copy="Latest normalized source results." /><FindingsTable results={w.findings} selectedId={w.selectedId} setSelectedId={w.setSelectedId} /></section></section>; }
function SearchWorkspace({ w }: { w: Workspace }) { const found = w.results.filter((f) => f.status === "found").length; const review = w.results.filter((f) => f.status === "unknown" || f.status === "skipped").length; return <><section className="search-panel"><form onSubmit={w.runSearch}><div className="tabs">{(["username", "email", "domain", "ip", "phone"] as TargetType[]).map((t) => <button type="button" key={t} className={w.targetType === t ? "tab active" : "tab"} onClick={() => w.setTargetType(t)}>{t}</button>)}</div><div className="search-row"><label>Target<input value={w.target} onChange={(e) => w.setTarget(e.target.value)} placeholder="username, email, domain, IP, or phone" /></label><button className="primary-button" disabled={w.loading}><Search size={18} />{w.loading ? "Searching" : "Run search"}</button></div><label className="consent-row"><input type="checkbox" checked={w.consent} onChange={(e) => w.setConsent(e.target.checked)} />Authorized business use and consent confirmed</label>{w.error && <div className="error-state">{w.error}</div>}</form></section><section className="dashboard-grid"><section className="results-panel"><div className="metric-strip"><Metric label="Checks" value={String(w.results.length)} /><Metric label="Found" value={String(found)} /><Metric label="Review" value={String(review)} /></div><div className="filter-row"><span>Category</span>{w.categories.map((c) => <button key={c} className={w.category === c ? "mini-tab active" : "mini-tab"} onClick={() => w.setCategory(c)}>{c}</button>)}</div><FindingsTable results={w.results} selectedId={w.selectedId} setSelectedId={w.setSelectedId} /></section><EvidencePanel selected={w.selected} exportReport={w.exportReport} /></section></>; }
function FindingsTable({ results, selectedId, setSelectedId }: { results: Finding[]; selectedId: string; setSelectedId: (id: string) => void }) { return <div className="table-wrap"><table><thead><tr><th>Source</th><th>Category</th><th>Status</th><th>Confidence</th></tr></thead><tbody>{results.map((f) => <tr key={f.id} className={f.id === selectedId ? "selected" : ""} onClick={() => setSelectedId(f.id)}><td>{f.source}</td><td>{f.category}</td><td><span className={`status ${f.status}`}>{f.status.replace("_", " ")}</span></td><td>{Math.round(f.confidence * 100)}%</td></tr>)}</tbody></table></div>; }
function EvidencePanel({ selected, exportReport }: { selected?: Finding; exportReport: (f: string) => void }) { if (!selected) return <aside className="detail-panel"><p className="empty-state">Select a finding to inspect evidence.</p></aside>; return <aside className="detail-panel"><div className="detail-header"><Activity size={20} /><div><h2>{selected.title}</h2><p>{selected.source}</p></div></div><div className="confidence"><span>Confidence</span><strong>{Math.round(selected.confidence * 100)}%</strong></div><p className="evidence">{selected.evidence}</p>{selected.url && <a className="source-link" href={selected.url} target="_blank" rel="noreferrer">Open source URL</a>}<div className="flag-list">{selected.compliance_flags.map((flag) => <span key={flag}>{flag.replaceAll("_", " ")}</span>)}</div><div className="button-row"><button className="secondary-button" onClick={() => exportReport("json")}><FileDown size={18} />JSON</button><button className="secondary-button" onClick={() => exportReport("csv")}><FileDown size={18} />CSV</button></div></aside>; }
function ReportsView({ w }: { w: Workspace }) { return <section className="content-panel"><SectionTitle eyebrow="Reports" title="Latest report package" copy="Export normalized evidence for review." /><div className="report-grid"><Metric label="Target" value={w.target} /><Metric label="Findings" value={String(w.findings.length)} /><Metric label="Generated" value={new Date().toLocaleString()} /></div><div className="button-row left"><button className="primary-button" onClick={() => w.exportReport("json")}><FileDown size={18} />Export JSON</button><button className="secondary-button compact" onClick={() => w.exportReport("csv")}>Export CSV</button></div></section>; }
function SourcesView({ sources, health = [] }: { sources: typeof fallbackSources; health?: SourceHealth[] }) { const healthById = Object.fromEntries(health.map((item) => [item.source_id, item])); return <section className="content-panel"><SectionTitle eyebrow="Sources" title="Enabled data sources" copy="Review source readiness and health before running paid provider searches." /><div className="source-list">{sources.map((s) => { const h = healthById[s.id]; return <article className="source-card" key={s.id}><div><h2>{s.name}</h2><p>Provider category: {s.category}. Keep enabled only when terms, consent, and credentials are approved.</p></div><span className={`status ${s.status}`}>{s.status.replaceAll("_", " ")}</span><dl><dt>Category</dt><dd>{s.category}</dd><dt>Health</dt><dd>{h ? `${h.status}${h.latency_ms ? ` / ${h.latency_ms} ms` : ""}` : "Not checked"}</dd><dt>Storage</dt><dd>Normalized evidence only</dd></dl></article>; })}</div></section>; }
function MemberBillingPage({ summary }: { summary: MemberDashboardSummary | null }) { const [message, setMessage] = React.useState(""); const [checkoutUrl, setCheckoutUrl] = React.useState(""); async function checkout(plan: string) { setMessage(""); setCheckoutUrl(""); try { const response = await api<PayPalCheckoutResponse>("/api/member/billing/checkout", { method: "POST", body: JSON.stringify({ plan }) }); setCheckoutUrl(response.checkout_url); setMessage(response.message); } catch (err) { setMessage(err instanceof Error ? err.message : "Checkout failed"); } } return <section className="content-panel"><SectionTitle eyebrow="Billing" title={summary ? `${summary.plan.name} plan` : "Plan and payment"} copy={summary ? `${summary.plan.monthly_search_limit.toLocaleString()} searches per month. Billing status: ${summary.billing_status}.` : "Loading billing state."} /><div className="report-grid"><Metric label="Plan" value={summary?.plan.name ?? "-"} /><Metric label="Price" value={summary ? `$${summary.plan.amount}` : "-"} /><Metric label="Interval" value={summary?.plan.interval ?? "-"} /></div><ul className="price-services">{(summary?.plan_features ?? []).map((feature) => <li key={feature}>{feature}</li>)}</ul><div className="button-row left"><button className="primary-button" type="button" onClick={() => checkout(summary?.plan.id ?? "growth")}><CreditCard size={18} />Open PayPal checkout</button>{checkoutUrl && <a className="secondary-button compact" href={checkoutUrl} target="_blank" rel="noreferrer">Continue to PayPal</a>}</div>{message && <p className="success-state">{message}</p>}</section>; }
function MemberAccountPage({ summary }: { summary: MemberDashboardSummary | null }) { return <section className="content-panel"><SectionTitle eyebrow="Account" title={summary?.user.email ?? "Member account"} copy="Account identity, role, tenant, and access state." /><div className="table-wrap"><table><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>Username</td><td>{summary?.user.username ?? "-"}</td></tr><tr><td>Email</td><td>{summary?.user.email ?? "-"}</td></tr><tr><td>Role</td><td>{summary?.user.role ?? "-"}</td></tr><tr><td>Tenant</td><td>{summary?.tenant.name ?? "-"}</td></tr><tr><td>Plan</td><td>{summary?.plan.name ?? "-"}</td></tr><tr><td>Status</td><td><span className={`status ${summary?.user.active ? "active" : "disabled"}`}>{summary?.user.active ? "active" : "disabled"}</span></td></tr></tbody></table></div></section>; }
function AdminOverview({ w }: { w: Workspace }) { const [checklist, setChecklist] = React.useState<LaunchChecklistItem[]>([]); const [hardening, setHardening] = React.useState<DeploymentHardeningStatus | null>(null); const [providers, setProviders] = React.useState<ProviderConfig[]>([]); const [users, setUsers] = React.useState<UserAccountView[]>([]); React.useEffect(() => { Promise.all([api<LaunchChecklistItem[]>('/api/admin/launch-checklist'), api<DeploymentHardeningStatus>('/api/admin/hardening'), api<ProviderConfig[]>('/api/admin/provider-configs'), api<UserAccountView[]>('/api/admin/users')]).then(([c, h, p, u]) => { setChecklist(c); setHardening(h); setProviders(p); setUsers(u); }).catch(() => undefined); }, []); const done = checklist.filter((item) => item.status === 'done').length; const needsKeys = providers.filter((item) => item.status === 'needs_api_key').length; const activeUsers = users.filter((item) => item.active).length; return <section className="admin-grid"><article className="content-panel"><SectionTitle eyebrow="Admin" title="Readiness controls" copy={`${done}/${checklist.length || 1} platform controls active.`} /><ul className="check-list">{checklist.map((item) => <li key={item.id}><strong>{item.label}</strong> - {item.status}: {item.note}</li>)}</ul></article><article className="content-panel"><SectionTitle eyebrow="Operations" title="Dashboard health" /><div className="metric-strip cards"><Metric label="Active users" value={String(activeUsers)} /><Metric label="Providers" value={String(providers.length)} /><Metric label="Credential refs" value={String(providers.length - needsKeys)} /></div><div className="contract-box"><LockKeyhole size={18} /><span>{hardening?.note ?? 'Security status loading.'}</span></div></article><article className="content-panel wide"><SectionTitle eyebrow="Sources" title={`${w.sources.length} source slots`} /><div className="readiness-row">{w.sources.map((s) => <span className={`status ${s.status}`} key={s.id}>{s.name}: {s.status.replaceAll('_', ' ')}</span>)}</div></article></section>; }
function SettingsPanel({ title, children }: { title: string; children: React.ReactNode }) { return <section className="content-panel settings-panel"><h2>{title}</h2><div className="form-stack">{children}</div></section>; }
function GeneralSettings() { const [settings, setSettings] = React.useState<GeneralSettingsState>({ application_name: "Social Hunter", public_url: "https://social-hunter.spunwebtechnology.com/", support_email: PAYPAL_EMAIL, default_plan: "growth", require_consent: true, normalized_evidence_only: true, high_cost_provider_approval: true, export_retention_days: 90 }); const [message, setMessage] = React.useState(""); const [busy, setBusy] = React.useState(false); React.useEffect(() => { api<GeneralSettingsState>("/api/admin/settings/general").then(setSettings).catch((err) => setMessage(err instanceof Error ? err.message : "Could not load settings")); }, []); async function save(e: React.FormEvent) { e.preventDefault(); setBusy(true); try { const saved = await api<GeneralSettingsState>("/api/admin/settings/general", { method: "PUT", body: JSON.stringify(settings) }); setSettings(saved); setMessage("General settings saved."); } catch (err) { setMessage(err instanceof Error ? err.message : "Save failed"); } finally { setBusy(false); } } return <form className="settings-grid" onSubmit={save}><SettingsPanel title="General settings"><label>Application name<input value={settings.application_name} onChange={(e) => setSettings({ ...settings, application_name: e.target.value })} /></label><label>Public URL<input value={settings.public_url} onChange={(e) => setSettings({ ...settings, public_url: e.target.value })} /></label><label>Support email<input value={settings.support_email} onChange={(e) => setSettings({ ...settings, support_email: e.target.value })} /></label><label>Default plan<select value={settings.default_plan} onChange={(e) => setSettings({ ...settings, default_plan: e.target.value })}><option value="starter">Starter</option><option value="growth">Growth</option><option value="operator">Operator</option></select></label><button className="primary-button" disabled={busy}><Settings size={18} />{busy ? "Saving" : "Save general settings"}</button>{message && <p className="success-state">{message}</p>}</SettingsPanel><SettingsPanel title="Search policy"><label><input type="checkbox" checked={settings.require_consent} onChange={(e) => setSettings({ ...settings, require_consent: e.target.checked })} /> Require consent confirmation before search</label><label><input type="checkbox" checked={settings.normalized_evidence_only} onChange={(e) => setSettings({ ...settings, normalized_evidence_only: e.target.checked })} /> Store normalized evidence only</label><label><input type="checkbox" checked={settings.high_cost_provider_approval} onChange={(e) => setSettings({ ...settings, high_cost_provider_approval: e.target.checked })} /> Require approval for high-cost providers</label><label>Export retention days<input type="number" min={1} value={settings.export_retention_days} onChange={(e) => setSettings({ ...settings, export_retention_days: Number(e.target.value) })} /></label></SettingsPanel></form>; }
function CompliancePage() { const [settings, setSettings] = React.useState<ComplianceSettingsState>({ tenant_controls_enabled: true, require_consent_record: true, require_source_attribution: true, default_use_case: "authorized_business_research", allowed_geographies: ["United States"], approval_required_for_sensitive_sources: true, reviewer_role_enabled: true, note: "Source access is gated by tenant, provider terms, geography, and approved use case." }); const [geoText, setGeoText] = React.useState("United States"); const [message, setMessage] = React.useState(""); const [busy, setBusy] = React.useState(false); React.useEffect(() => { api<ComplianceSettingsState>("/api/admin/settings/compliance").then((s) => { setSettings(s); setGeoText(s.allowed_geographies.join("\n")); }).catch((err) => setMessage(err instanceof Error ? err.message : "Could not load compliance settings")); }, []); async function save(e: React.FormEvent) { e.preventDefault(); setBusy(true); setMessage(""); try { const payload = { ...settings, allowed_geographies: geoText.split(/\r?\n|,/).map((item) => item.trim()).filter(Boolean) }; const saved = await api<ComplianceSettingsState>("/api/admin/settings/compliance", { method: "PUT", body: JSON.stringify(payload) }); setSettings(saved); setGeoText(saved.allowed_geographies.join("\n")); setMessage("Compliance controls saved."); } catch (err) { setMessage(err instanceof Error ? err.message : "Compliance save failed"); } finally { setBusy(false); } } return <form className="settings-grid" onSubmit={save}><SettingsPanel title="Tenant and use controls"><label className="toggle-row"><input type="checkbox" checked={settings.tenant_controls_enabled} onChange={(e) => setSettings({ ...settings, tenant_controls_enabled: e.target.checked })} /><span>Enable tenant-level source controls</span><em>Access</em></label><label className="toggle-row"><input type="checkbox" checked={settings.reviewer_role_enabled} onChange={(e) => setSettings({ ...settings, reviewer_role_enabled: e.target.checked })} /><span>Enable read-only reviewer role</span><em>Roles</em></label><label>Default approved use case<input value={settings.default_use_case} onChange={(e) => setSettings({ ...settings, default_use_case: e.target.value })} /></label><label>Allowed geographies<textarea rows={5} value={geoText} onChange={(e) => setGeoText(e.target.value)} /></label></SettingsPanel><SettingsPanel title="Evidence and source policy"><label className="toggle-row"><input type="checkbox" checked={settings.require_consent_record} onChange={(e) => setSettings({ ...settings, require_consent_record: e.target.checked })} /><span>Require consent confirmation record</span><em>Search</em></label><label className="toggle-row"><input type="checkbox" checked={settings.require_source_attribution} onChange={(e) => setSettings({ ...settings, require_source_attribution: e.target.checked })} /><span>Require source attribution in reports</span><em>Reports</em></label><label className="toggle-row"><input type="checkbox" checked={settings.approval_required_for_sensitive_sources} onChange={(e) => setSettings({ ...settings, approval_required_for_sensitive_sources: e.target.checked })} /><span>Require approval for sensitive sources</span><em>Review</em></label><label>Admin note<textarea rows={4} value={settings.note} onChange={(e) => setSettings({ ...settings, note: e.target.value })} /></label><button className="primary-button" disabled={busy}><ShieldCheck size={18} />{busy ? "Saving" : "Save compliance controls"}</button>{message && <p className="success-state">{message}</p>}</SettingsPanel></form>; }
function UsageControlsPage() { const [settings, setSettings] = React.useState<UsageControlSettingsState>({ queue_enabled: true, max_concurrent_jobs: 4, monthly_cost_alert_threshold: 250, high_cost_provider_alerts: true, notify_billing_contact: true, automatic_pause_on_limit: true, note: "Usage caps and alerts protect paid provider credits from accidental overuse." }); const [message, setMessage] = React.useState(""); const [busy, setBusy] = React.useState(false); React.useEffect(() => { api<UsageControlSettingsState>("/api/admin/settings/usage-controls").then(setSettings).catch((err) => setMessage(err instanceof Error ? err.message : "Could not load usage controls")); }, []); async function save(e: React.FormEvent) { e.preventDefault(); setBusy(true); setMessage(""); try { const saved = await api<UsageControlSettingsState>("/api/admin/settings/usage-controls", { method: "PUT", body: JSON.stringify(settings) }); setSettings(saved); setMessage("Usage controls saved."); } catch (err) { setMessage(err instanceof Error ? err.message : "Usage controls save failed"); } finally { setBusy(false); } } return <form className="settings-grid" onSubmit={save}><SettingsPanel title="Queue controls"><label className="toggle-row"><input type="checkbox" checked={settings.queue_enabled} onChange={(e) => setSettings({ ...settings, queue_enabled: e.target.checked })} /><span>Queue long-running searches</span><em>Jobs</em></label><label>Max concurrent jobs<input type="number" min={1} max={50} value={settings.max_concurrent_jobs} onChange={(e) => setSettings({ ...settings, max_concurrent_jobs: Number(e.target.value) })} /></label><label className="toggle-row"><input type="checkbox" checked={settings.automatic_pause_on_limit} onChange={(e) => setSettings({ ...settings, automatic_pause_on_limit: e.target.checked })} /><span>Pause tenant usage when limits are reached</span><em>Limits</em></label></SettingsPanel><SettingsPanel title="Cost and alert controls"><label>Monthly cost alert threshold<input type="number" min={0} step="0.01" value={settings.monthly_cost_alert_threshold} onChange={(e) => setSettings({ ...settings, monthly_cost_alert_threshold: Number(e.target.value) })} /></label><label className="toggle-row"><input type="checkbox" checked={settings.high_cost_provider_alerts} onChange={(e) => setSettings({ ...settings, high_cost_provider_alerts: e.target.checked })} /><span>Alert on high-cost provider use</span><em>Spend</em></label><label className="toggle-row"><input type="checkbox" checked={settings.notify_billing_contact} onChange={(e) => setSettings({ ...settings, notify_billing_contact: e.target.checked })} /><span>Notify billing contact on alerts</span><em>Mail</em></label><label>Admin note<textarea rows={4} value={settings.note} onChange={(e) => setSettings({ ...settings, note: e.target.value })} /></label><button className="primary-button" disabled={busy}><SlidersHorizontal size={18} />{busy ? "Saving" : "Save usage controls"}</button>{message && <p className="success-state">{message}</p>}</SettingsPanel></form>; }
function ApiSettings() { const [providers, setProviders] = React.useState<ProviderConfig[]>([]); const [keys, setKeys] = React.useState<ApiKeyReference[]>([]); const [gates, setGates] = React.useState<SourceGate[]>([]); const [message, setMessage] = React.useState(""); const [busy, setBusy] = React.useState(false); React.useEffect(() => { Promise.all([api<ProviderConfig[]>("/api/admin/provider-configs"), api<ApiKeyReference[]>("/api/admin/settings/api-keys"), api<SourceGate[]>("/api/admin/settings/source-gates")]).then(([p, k, g]) => { setProviders(p); setKeys(k); setGates(g); }).catch((err) => setMessage(err instanceof Error ? err.message : "Could not load integration configuration")); }, []); function updateKey(i: number, patch: Partial<ApiKeyReference>) { setKeys(keys.map((key, index) => index === i ? { ...key, ...patch } : key)); } function updateGate(sourceId: string, patch: Partial<SourceGate>) { setGates(gates.map((gate) => gate.source_id === sourceId ? { ...gate, ...patch } : gate)); } async function saveAll() { setBusy(true); try { const [savedKeys, savedGates] = await Promise.all([api<ApiKeyReference[]>("/api/admin/settings/api-keys", { method: "PUT", body: JSON.stringify(keys) }), api<SourceGate[]>("/api/admin/settings/source-gates", { method: "PUT", body: JSON.stringify(gates) })]); setKeys(savedKeys); setGates(savedGates); setMessage("Integration references and source gates saved."); } catch (err) { setMessage(err instanceof Error ? err.message : "Save failed"); } finally { setBusy(false); } } async function testKey(key: ApiKeyReference) { try { const result = await api<{ ok: boolean; message: string; connector_function: string }>("/api/admin/settings/api-keys/test", { method: "POST", body: JSON.stringify({ provider: key.provider, provider_id: key.provider_id, credential_type: key.credential_type, vault_reference: key.vault_reference }) }); setMessage(`${key.provider}: ${result.message} (${result.connector_function})`); } catch (err) { setMessage(err instanceof Error ? err.message : "Test failed"); } } const grouped = providers.reduce<Record<string, ProviderConfig[]>>((acc, provider) => { acc[provider.category] = acc[provider.category] ?? []; acc[provider.category].push(provider); return acc; }, {}); return <section className="admin-stack"><section className="content-panel"><SectionTitle eyebrow="Provider map" title="Provider integrations and connector functions" copy="Every source is mapped to a connector function, source gate, secure credential reference, and optional provider route." /><div className="button-row no-pad"><button className="primary-button" type="button" onClick={saveAll} disabled={busy}><KeyRound size={18} />{busy ? "Saving" : "Save integration configuration"}</button></div>{message && <p className="success-state">{message}</p>}</section>{Object.entries(grouped).map(([category, list]) => <section className="content-panel" key={category}><SectionTitle eyebrow="Source category" title={category.replaceAll("_", " ")} /><div className="provider-grid">{list.map((provider) => { const gate = gates.find((g) => g.source_id === provider.id); const providerKeys = keys.map((key, index) => ({ key, index })).filter(({ key }) => key.provider_id === provider.id); return <article className="provider-card" key={provider.id}><div className="provider-card-head"><div><h3>{provider.name}</h3><p>{provider.note || provider.terms_note}</p></div><span className={`status ${provider.status}`}>{provider.status.replaceAll("_", " ")}</span></div><dl><dt>Function</dt><dd>{provider.connector_function}</dd><dt>Returns</dt><dd>{provider.data_returned.join(", ")}</dd><dt>Route</dt><dd>{provider.proxy_route_supported ? "Allowed provider route" : "Direct API or local route"}</dd></dl><label className="toggle-row"><input type="checkbox" checked={gate?.enabled ?? false} onChange={(e) => updateGate(provider.id, { enabled: e.target.checked })} /><span>Enable source gate</span><em>{gate?.tenant_plan ?? "operator"}</em></label><label className="toggle-row"><input type="checkbox" checked={gate?.requires_approval ?? true} onChange={(e) => updateGate(provider.id, { requires_approval: e.target.checked })} /><span>Require approval</span><em>control</em></label>{providerKeys.map(({ key, index }) => <div className="secret-row" key={`${key.provider_id}-${key.credential_type}`}><div><strong>{key.credential_type}</strong><span>{key.notes || "Secure credential reference required"}</span></div><input value={key.vault_reference.replace(/^VAULT_REF_/, "SECURE_REF_")} disabled={key.credential_type === "none"} placeholder="SECURE_REF_PROVIDER_KEY" onChange={(e) => updateKey(index, { vault_reference: e.target.value })} /><label className="inline-check"><input type="checkbox" checked={key.enabled} onChange={(e) => updateKey(index, { enabled: e.target.checked })} /> Enabled</label><button className="secondary-button compact" type="button" onClick={() => testKey(key)}>Test</button></div>)}</article>; })}</div></section>)}</section>; }
function RouteSettings() { const [settings, setSettings] = React.useState<RouteSettingsState>({ mode: "off", manual_entries: [], use_only_for_allowlisted_egress: true, disable_failed_proxies: true, require_admin_approval: false, health_check_interval_minutes: 30 }); const [routes, setRoutes] = React.useState<RouteRouteRule[]>([]); const [importText, setImportText] = React.useState(""); const [targetUrl, setTargetUrl] = React.useState("https://api.ipify.org?format=json"); const [connectionResults, setConnectionResults] = React.useState<RouteConnectionResult[]>([]); const [message, setMessage] = React.useState(""); const [busy, setBusy] = React.useState(false); const [testingConnections, setTestingConnections] = React.useState(false); React.useEffect(() => { Promise.all([api<RouteSettingsState>("/api/admin/settings/proxies"), api<RouteRouteRule[]>("/api/admin/settings/proxies/routes")]).then(([s, r]) => { setSettings(s); setRoutes(r); setImportText(s.manual_entries.join("\n")); }).catch((err) => setMessage(err instanceof Error ? err.message : "Could not load provider routing settings")); }, []); function currentEntries() { return importText.split(/\r?\n/).map((line) => line.trim()).filter((line) => line && !line.startsWith("#")); } function updateRoute(id: string, patch: Partial<RouteRouteRule>) { setRoutes(routes.map((route) => route.id === id ? { ...route, ...patch } : route)); } async function importEntries() { try { const saved = await api<RouteSettingsState>("/api/admin/settings/proxies/import", { method: "POST", body: JSON.stringify({ entries_text: importText }) }); setSettings(saved); setMessage(`Imported ${saved.manual_entries.length} route entries.`); } catch (err) { setMessage(err instanceof Error ? err.message : "Provider route import failed"); } } async function testRoute() { try { const candidate = { ...settings, manual_entries: currentEntries() }; const result = await api<{ ok: boolean; tested: number; valid_format: number; invalid_entries: string[]; message: string }>("/api/admin/settings/proxies/test", { method: "POST", body: JSON.stringify(candidate) }); setMessage(`${result.message} Valid ${result.valid_format}/${result.tested}; invalid ${result.invalid_entries.length}.`); } catch (err) { setMessage(err instanceof Error ? err.message : "Provider route validation failed"); } } async function testConnections() { const entries = currentEntries(); setTestingConnections(true); setConnectionResults([]); setMessage(""); try { const result = await api<RouteConnectionTestResponse>("/api/admin/settings/proxies/connection-test", { method: "POST", body: JSON.stringify({ entries, target_url: targetUrl, timeout_seconds: 8, concurrency: 4 }) }); setConnectionResults(result.results); setMessage(result.message); } catch (err) { setMessage(err instanceof Error ? err.message : "Provider route connection test failed"); } finally { setTestingConnections(false); } } async function saveAll() { setBusy(true); try { const nextSettings = { ...settings, manual_entries: currentEntries() }; const [savedSettings, savedRoutes] = await Promise.all([api<RouteSettingsState>("/api/admin/settings/proxies", { method: "PUT", body: JSON.stringify(nextSettings) }), api<RouteRouteRule[]>("/api/admin/settings/proxies/routes", { method: "PUT", body: JSON.stringify(routes) })]); setSettings(savedSettings); setRoutes(savedRoutes); setImportText(savedSettings.manual_entries.join("\n")); setMessage("Route settings and routes saved."); } catch (err) { setMessage(err instanceof Error ? err.message : "Provider route save failed"); } finally { setBusy(false); } } const connected = connectionResults.filter((item) => item.ok).length; return <section className="settings-grid"><SettingsPanel title="Route configuration"><label>Mode<select value={settings.mode} onChange={(e) => setSettings({ ...settings, mode: e.target.value as RouteSettingsState["mode"] })}><option value="off">Off</option><option value="provider">Provider managed</option><option value="manual">Manual list</option></select></label><label>Manual import<textarea className="textarea-code" rows={7} value={importText} onChange={(e) => setImportText(e.target.value)} placeholder="host:port:user:password, one per line" /></label><label>Import by file<input type="file" accept=".txt,.csv" onChange={async (e) => { const file = e.target.files?.[0]; if (file) setImportText(await file.text()); }} /></label><label>Connection test URL<input value={targetUrl} onChange={(e) => setTargetUrl(e.target.value)} placeholder="https://api.ipify.org?format=json" /></label><div className="button-row no-pad"><button type="button" className="secondary-button compact" onClick={importEntries}><SlidersHorizontal size={18} />Import list</button><button type="button" className="secondary-button compact" onClick={testRoute}><Network size={18} />Validate format</button><button type="button" className="secondary-button compact" onClick={testConnections} disabled={testingConnections}><Network size={18} />{testingConnections ? "Testing" : "Test connections"}</button><button type="button" className="primary-button" onClick={saveAll} disabled={busy}><Network size={18} />{busy ? "Saving" : "Save route rules"}</button></div>{message && <p className="success-state">{message}</p>}{connectionResults.length > 0 && <div className="proxy-test-results"><div className="metric-strip cards"><Metric label="Tested" value={String(connectionResults.length)} /><Metric label="Connected" value={String(connected)} /><Metric label="Needs review" value={String(connectionResults.length - connected)} /></div><div className="table-wrap"><table><thead><tr><th>Route</th><th>Status</th><th>Latency</th><th>HTTP</th><th>Result</th></tr></thead><tbody>{connectionResults.map((result) => <tr key={`${result.index}-${result.proxy}`}><td>{result.proxy}</td><td><span className={`status ${result.status === "connected" ? "ready" : result.status === "invalid_format" ? "error" : "needs_api_key"}`}>{result.status.replaceAll("_", " ")}</span></td><td>{result.latency_ms ? `${result.latency_ms} ms` : "-"}</td><td>{result.http_status ?? "-"}</td><td>{result.error || "Connected"}</td></tr>)}</tbody></table></div></div>}</SettingsPanel><SettingsPanel title="Route rules"><label><input type="checkbox" checked={settings.use_only_for_allowlisted_egress} onChange={(e) => setSettings({ ...settings, use_only_for_allowlisted_egress: e.target.checked })} /> Use provider routes only for allowlisted API egress</label><label><input type="checkbox" checked={settings.disable_failed_proxies} onChange={(e) => setSettings({ ...settings, disable_failed_proxies: e.target.checked })} /> Disable failed proxies after repeated connection errors</label><label><input type="checkbox" checked={settings.require_admin_approval} onChange={(e) => setSettings({ ...settings, require_admin_approval: e.target.checked })} /> Require admin approval before enabling a route list</label><label>Health check interval<select value={settings.health_check_interval_minutes} onChange={(e) => setSettings({ ...settings, health_check_interval_minutes: Number(e.target.value) })}><option value={15}>15 minutes</option><option value={30}>30 minutes</option><option value={60}>60 minutes</option></select></label>{routes.map((route) => <article className="route-card" key={route.id}><label className="toggle-row"><input type="checkbox" checked={route.enabled} onChange={(e) => updateRoute(route.id, { enabled: e.target.checked })} /><span>{route.label}</span><em>{route.category}</em></label><label className="toggle-row"><input type="checkbox" checked={route.proxy_required} onChange={(e) => updateRoute(route.id, { proxy_required: e.target.checked })} /><span>Require configured route for this provider</span><em>{route.provider_ids.length} providers</em></label><p>{route.note}</p><small>{route.allowed_domains.join(", ")}</small></article>)}</SettingsPanel></section>; }
function ContactMail() { const [msgs, setMsgs] = React.useState<ContactSubmissionRecord[]>([]); const [settings, setSettings] = React.useState<MailSettingsState>({ provider: "smtp_or_api", from_email: "support@spunwebtechnology.com", smtp_api_key_ref: "SECURE_REF_SOCIAL_HUNTER_SMTP_API_KEY", password_reset_enabled: true, contact_notifications_enabled: true }); const [message, setMessage] = React.useState(""); const [error, setError] = React.useState(""); React.useEffect(() => { Promise.all([api<ContactSubmissionRecord[]>("/api/admin/contact-submissions"), api<MailSettingsState>("/api/admin/settings/mail")]).then(([m, s]) => { setMsgs(m); setSettings(s); }).catch((err) => setError(err instanceof Error ? err.message : "Could not load mail settings")); }, []); async function saveMail(e: React.FormEvent) { e.preventDefault(); setMessage(""); try { const saved = await api<MailSettingsState>("/api/admin/settings/mail", { method: "PUT", body: JSON.stringify(settings) }); setSettings(saved); setMessage("Mail and reset settings saved."); } catch (err) { setError(err instanceof Error ? err.message : "Mail save failed"); } } return <section className="admin-stack"><form className="content-panel" onSubmit={saveMail}><SectionTitle eyebrow="Mail" title="Mail and reset configuration" copy="Configure sender identity, secure mail-provider reference, reset availability, and contact notifications." /><div className="settings-grid"><label>Provider<input value={settings.provider} onChange={(e) => setSettings({ ...settings, provider: e.target.value })} /></label><label>From email<input value={settings.from_email} onChange={(e) => setSettings({ ...settings, from_email: e.target.value })} /></label><label>SMTP/API secure reference<input value={settings.smtp_api_key_ref} onChange={(e) => setSettings({ ...settings, smtp_api_key_ref: e.target.value })} /></label><label className="toggle-row"><input type="checkbox" checked={settings.password_reset_enabled} onChange={(e) => setSettings({ ...settings, password_reset_enabled: e.target.checked })} /><span>Password reset email enabled</span><em>Auth</em></label><label className="toggle-row"><input type="checkbox" checked={settings.contact_notifications_enabled} onChange={(e) => setSettings({ ...settings, contact_notifications_enabled: e.target.checked })} /><span>Contact notifications enabled</span><em>Mail</em></label></div><button className="primary-button"><Mail size={18} />Save mail settings</button>{message && <p className="success-state">{message}</p>}{error && <p className="error-state">{error}</p>}</form><section className="content-panel"><SectionTitle eyebrow="Inbox" title="Contact form submissions" copy="Route public contact and signup requests into this mailbox." /><div className="table-wrap"><table><thead><tr><th>Name</th><th>Email</th><th>Company</th><th>Message</th><th>Status</th></tr></thead><tbody>{msgs.length === 0 && <tr><td colSpan={5}>No submissions yet.</td></tr>}{msgs.map((m) => <tr key={m.id}><td>{m.name}</td><td>{m.email}</td><td>{m.company}</td><td>{m.message}</td><td><span className={`status ${m.status}`}>{m.status}</span></td></tr>)}</tbody></table></div></section></section>; }
function UsersPage() { const [users, setUsers] = React.useState<UserAccountView[]>([]); const [tenants, setTenants] = React.useState<TenantAccount[]>([]); const [message, setMessage] = React.useState(""); const [error, setError] = React.useState(""); React.useEffect(() => { Promise.all([api<UserAccountView[]>("/api/admin/users"), api<TenantAccount[]>("/api/admin/tenants")]).then(([u, t]) => { setUsers(u); setTenants(t); }).catch((err) => setError(err instanceof Error ? err.message : "Could not load users")); }, []); function updateTenant(index: number, patch: Partial<TenantAccount>) { setTenants(tenants.map((tenant, i) => i === index ? { ...tenant, ...patch } : tenant)); } function addTenant() { const next = tenants.length + 1; setTenants([...tenants, { id: `tenant-${next}`, name: `Tenant ${next}`, plan: "growth", monthly_search_limit: 1500, status: "pending" }]); } async function saveTenants() { setMessage(""); try { const saved = await api<TenantAccount[]>("/api/admin/tenants", { method: "PUT", body: JSON.stringify(tenants) }); setTenants(saved); setMessage("Tenant access settings saved."); } catch (err) { setError(err instanceof Error ? err.message : "Tenant save failed"); } } return <section className="admin-stack"><section className="content-panel"><SectionTitle eyebrow="Users" title="Members and roles" copy="Live account list with role, tenant, lockout, and active status." />{error && <p className="error-state">{error}</p>}<div className="table-wrap"><table><thead><tr><th>User</th><th>Email</th><th>Role</th><th>Tenant</th><th>Plan</th><th>Status</th></tr></thead><tbody>{users.length === 0 && <tr><td colSpan={6}>No users loaded.</td></tr>}{users.map((u) => <tr key={u.username}><td>{u.username}</td><td>{u.email}</td><td>{u.role}</td><td>{u.tenant_id}</td><td>{u.plan}</td><td><span className={`status ${u.active ? "active" : "disabled"}`}>{u.active ? "active" : "disabled"}{u.locked_until ? " / locked" : ""}</span></td></tr>)}</tbody></table></div></section><section className="content-panel"><SectionTitle eyebrow="Tenants" title="Client plans and access" copy="Set each client tenant plan, usage limit, and billing/access status." /><div className="button-row no-pad"><button type="button" className="secondary-button compact" onClick={addTenant}><UsersRound size={18} />Add tenant</button><button type="button" className="primary-button" onClick={saveTenants}><Settings size={18} />Save tenants</button></div>{message && <p className="success-state">{message}</p>}<div className="tenant-grid">{tenants.map((tenant, index) => <article className="route-card" key={tenant.id}><label>Tenant ID<input value={tenant.id} onChange={(e) => updateTenant(index, { id: e.target.value })} /></label><label>Name<input value={tenant.name} onChange={(e) => updateTenant(index, { name: e.target.value })} /></label><label>Plan<select value={tenant.plan} onChange={(e) => updateTenant(index, { plan: e.target.value })}><option value="starter">Starter</option><option value="growth">Growth</option><option value="operator">Operator</option></select></label><label>Monthly search limit<input type="number" min={0} value={tenant.monthly_search_limit} onChange={(e) => updateTenant(index, { monthly_search_limit: Number(e.target.value) })} /></label><label>Status<select value={tenant.status} onChange={(e) => updateTenant(index, { status: e.target.value as TenantAccount["status"] })}><option value="active">Active</option><option value="pending">Pending</option><option value="suspended">Suspended</option></select></label></article>)}</div></section></section>; }
function BillingPage() { const [settings, setSettings] = React.useState<PayPalSettingsState>({ receiver_email: PAYPAL_EMAIL, webhook_secret_ref: "SECURE_REF_PAYPAL_WEBHOOK_SECRET", subscriptions_enabled: false, webhook_verified: false, currency: "USD", checkout_mode: "paypal_button", billing_contact_email: PAYPAL_EMAIL, terms_url: "https://social-hunter.spunwebtechnology.com/#pricing", success_url: "https://social-hunter.spunwebtechnology.com/members/", cancel_url: "https://social-hunter.spunwebtechnology.com/#pricing", plans: defaultBillingPlans }); const [message, setMessage] = React.useState(""); const [busy, setBusy] = React.useState(false); React.useEffect(() => { api<PayPalSettingsState>("/api/admin/settings/paypal").then(setSettings).catch((err) => setMessage(err instanceof Error ? err.message : "Could not load billing settings")); }, []); function updateSettings(patch: Partial<PayPalSettingsState>) { setSettings({ ...settings, ...patch }); } function updatePlan(index: number, patch: Partial<BillingPlan>) { setSettings({ ...settings, plans: settings.plans.map((plan, i) => i === index ? { ...plan, ...patch } : plan) }); } function updateService(planIndex: number, serviceIndex: number, value: string) { updatePlan(planIndex, { services: settings.plans[planIndex].services.map((service, i) => i === serviceIndex ? value : service) }); } function addService(planIndex: number) { updatePlan(planIndex, { services: [...settings.plans[planIndex].services, "New included service"] }); } function removeService(planIndex: number, serviceIndex: number) { updatePlan(planIndex, { services: settings.plans[planIndex].services.filter((_, i) => i !== serviceIndex) }); } function addPlan() { const next = settings.plans.length + 1; setSettings({ ...settings, plans: [...settings.plans, { id: `custom-${next}`, name: `Custom ${next}`, amount: 99, currency: settings.currency || "USD", interval: "month", monthly_search_limit: 500, export_enabled: true, api_access_enabled: false, description: "Custom configurable Social Hunter plan.", services: ["Dashboard access"], enabled: true, public: false, paypal_item_name: `Social Hunter Custom ${next} Plan`, sort_order: next * 10 }] }); } function removePlan(index: number) { setSettings({ ...settings, plans: settings.plans.filter((_, i) => i !== index) }); } async function save(e: React.FormEvent) { e.preventDefault(); setBusy(true); setMessage(""); try { const saved = await api<PayPalSettingsState>("/api/admin/settings/paypal", { method: "PUT", body: JSON.stringify(settings) }); setSettings(saved); setMessage("Billing configuration saved. Public pricing and checkout now use these values."); } catch (err) { setMessage(err instanceof Error ? err.message : "Billing save failed"); } finally { setBusy(false); } } return <form className="admin-stack" onSubmit={save}><section className="content-panel"><SectionTitle eyebrow="Billing" title="PayPal and plan configuration" copy="Configure public prices, plan descriptions, included services, limits, checkout behavior, and billing status." /><div className="billing-settings-grid"><label>PayPal receiver email<input value={settings.receiver_email} onChange={(e) => updateSettings({ receiver_email: e.target.value })} /></label><label>Billing contact email<input value={settings.billing_contact_email} onChange={(e) => updateSettings({ billing_contact_email: e.target.value })} /></label><label>Currency<input value={settings.currency} maxLength={3} onChange={(e) => updateSettings({ currency: e.target.value.toUpperCase() })} /></label><label>Checkout mode<select value={settings.checkout_mode} onChange={(e) => updateSettings({ checkout_mode: e.target.value as PayPalSettingsState["checkout_mode"] })}><option value="paypal_button">PayPal button</option><option value="subscription">Subscription</option><option value="manual_invoice">Manual invoice</option></select></label><label>Webhook secret reference<input value={settings.webhook_secret_ref} onChange={(e) => updateSettings({ webhook_secret_ref: e.target.value })} /></label><label>Terms URL<input value={settings.terms_url} onChange={(e) => updateSettings({ terms_url: e.target.value })} /></label><label>Success URL<input value={settings.success_url} onChange={(e) => updateSettings({ success_url: e.target.value })} /></label><label>Cancel URL<input value={settings.cancel_url} onChange={(e) => updateSettings({ cancel_url: e.target.value })} /></label><label className="toggle-row"><input type="checkbox" checked={settings.subscriptions_enabled} onChange={(e) => updateSettings({ subscriptions_enabled: e.target.checked })} /><span>Subscriptions enabled</span><em>PayPal</em></label><label className="toggle-row"><input type="checkbox" checked={settings.webhook_verified} onChange={(e) => updateSettings({ webhook_verified: e.target.checked })} /><span>Webhook verified</span><em>Status</em></label></div><div className="button-row no-pad"><button className="secondary-button compact" type="button" onClick={addPlan}><CreditCard size={18} />Add plan</button><button className="primary-button" disabled={busy}><CreditCard size={18} />{busy ? "Saving billing" : "Save billing configuration"}</button></div>{message && <p className="success-state">{message}</p>}</section><section className="billing-plan-list">{settings.plans.map((plan, index) => <article className="content-panel billing-plan-editor" key={`${plan.id}-${index}`}><div className="provider-card-head"><div><span className="eyebrow">Plan</span><h3>{plan.name || plan.id}</h3></div><button className="secondary-button compact" type="button" onClick={() => removePlan(index)}>Remove</button></div><div className="billing-plan-grid"><label>Plan ID<input value={plan.id} onChange={(e) => updatePlan(index, { id: e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, "-") })} /></label><label>Name<input value={plan.name} onChange={(e) => updatePlan(index, { name: e.target.value })} /></label><label>Price<input type="number" min={0} step="0.01" value={plan.amount} onChange={(e) => updatePlan(index, { amount: Number(e.target.value) })} /></label><label>Currency<input maxLength={3} value={plan.currency} onChange={(e) => updatePlan(index, { currency: e.target.value.toUpperCase() })} /></label><label>Interval<select value={plan.interval} onChange={(e) => updatePlan(index, { interval: e.target.value as BillingPlan["interval"] })}><option value="month">Monthly</option><option value="year">Yearly</option><option value="one_time">One time</option></select></label><label>Monthly search limit<input type="number" min={0} value={plan.monthly_search_limit} onChange={(e) => updatePlan(index, { monthly_search_limit: Number(e.target.value) })} /></label><label>PayPal item name<input value={plan.paypal_item_name} onChange={(e) => updatePlan(index, { paypal_item_name: e.target.value })} /></label><label>Sort order<input type="number" value={plan.sort_order} onChange={(e) => updatePlan(index, { sort_order: Number(e.target.value) })} /></label><label className="wide-field">Description<textarea rows={3} value={plan.description} onChange={(e) => updatePlan(index, { description: e.target.value })} /></label><label className="toggle-row"><input type="checkbox" checked={plan.enabled} onChange={(e) => updatePlan(index, { enabled: e.target.checked })} /><span>Enabled</span><em>Availability</em></label><label className="toggle-row"><input type="checkbox" checked={plan.public} onChange={(e) => updatePlan(index, { public: e.target.checked })} /><span>Public pricing</span><em>Landing</em></label><label className="toggle-row"><input type="checkbox" checked={plan.export_enabled} onChange={(e) => updatePlan(index, { export_enabled: e.target.checked })} /><span>Exports</span><em>Feature</em></label><label className="toggle-row"><input type="checkbox" checked={plan.api_access_enabled} onChange={(e) => updatePlan(index, { api_access_enabled: e.target.checked })} /><span>API access</span><em>Feature</em></label></div><div className="service-editor"><div className="provider-card-head"><strong>Included services</strong><button className="secondary-button compact" type="button" onClick={() => addService(index)}>Add service</button></div>{plan.services.map((service, serviceIndex) => <div className="service-row" key={`${plan.id}-service-${serviceIndex}`}><input value={service} onChange={(e) => updateService(index, serviceIndex, e.target.value)} /><button className="secondary-button compact" type="button" onClick={() => removeService(index, serviceIndex)}>Remove</button></div>)}</div></article>)}</section></form>; }
function AuditPage() { const [events, setEvents] = React.useState<AuditEvent[]>([]); const [error, setError] = React.useState(""); React.useEffect(() => { api<AuditEvent[]>("/api/admin/audit").then(setEvents).catch((err) => setError(err instanceof Error ? err.message : "Could not load audit events")); }, []); return <section className="content-panel"><SectionTitle eyebrow="Audit" title="Audit and operations" copy="Track searches, exports, admin settings, integration tests, and routing changes." />{error && <p className="error-state">{error}</p>}<div className="table-wrap"><table><thead><tr><th>Action</th><th>Actor</th><th>Status</th><th>Metadata</th></tr></thead><tbody>{events.length === 0 && <tr><td colSpan={4}>No audit events yet.</td></tr>}{events.map((event, idx) => <tr key={idx}><td>{event.action ?? "event"}</td><td>{event.actor ?? "system"}</td><td><span className={`status ${event.status ?? "reviewed"}`}>{event.status ?? "recorded"}</span></td><td>{Object.entries(event).filter(([key]) => !["action", "actor", "status"].includes(key)).map(([key, value]) => `${key}: ${value}`).join(" | ")}</td></tr>)}</tbody></table></div></section>; }
function ContactForm() { const [form, setForm] = React.useState({ name: "", email: "", company: "", message: "" }); const [status, setStatus] = React.useState(""); async function submit(e: React.FormEvent) { e.preventDefault(); try { await api<ContactSubmissionRecord>("/api/contact", { method: "POST", body: JSON.stringify(form) }); setStatus("Request sent."); setForm({ name: "", email: "", company: "", message: "" }); } catch (err) { setStatus(err instanceof Error ? err.message : "Request failed"); } } return <form className="contact-form" onSubmit={submit}><label>Name<input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="Your name" /></label><label>Email<input value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} type="email" placeholder="you@company.com" /></label><label>Company<input value={form.company} onChange={(e) => setForm({ ...form, company: e.target.value })} placeholder="Company" /></label><label>Message<textarea value={form.message} onChange={(e) => setForm({ ...form, message: e.target.value })} rows={5} placeholder="Tell us what you need Social Hunter to help with." /></label><button className="primary-button full"><Mail size={18} />Send request</button>{status && <p className="success-state">{status}</p>}</form>; }
ReactDOM.createRoot(document.getElementById("root")!).render(<App />);
